combobox_labeled_RMC.script:
					local sOldValue = nil;
					local bIsRefreshing = false;
					
					function onInit()
						super.onInit();

						local nodeChar = window.getDatabaseNode();
						local sPath = DB.getPath(nodeChar, "inventorylist");
						DB.addHandler(sPath, "onChildUpdate", onChildUpdate);
						DB.addHandler(sPath .. ".*", "onDelete", onDelete);

						sOldValue = getValue();
						updateList();
						refreshFields();
					end

					function onValueChanged()
						refreshFields();
						sOldValue = getValue();
					end

					function onDelete(nodeToBeDeleted)
						local sItemName = ItemManager2.getDisplayName(nodeToBeDeleted);
						if sItemName == getValue() then
							setValue("");
						end
						refreshFields();
					end

					function onChildUpdate(nodeParent, nodeChildUpdated)
						handleNameChange();
						updateList();
						refreshFields();
					end

					function updateList()
						local nodeChar = window.getDatabaseNode();
						clear();
						addItems(ItemManager2.CharArmorList(nodeChar));
						refreshFields();
					end

					function refreshFields()
						if not bIsRefreshing then
							bIsRefreshing = true;
							local nodeChar = window.getDatabaseNode();
							local nodeInventoryList = DB.createChild(nodeChar, "inventorylist");
							local iMinMMPenalty = 0;
							local iMaxMMPenalty = 0;
							local iMissilePenalty = 0;
							local iQUPenalty = 0;
							local iAT = 1;
							window.equipped_armor_link.setValue();

							if nodeInventoryList then
								for _, vItem in pairs(DB.getChildren(nodeChar, "inventorylist")) do
									local sItemType = DB.getValue(vItem, "type", "");
									if sItemType == "Armor" then
										local sItemName = ItemManager2.getDisplayName(vItem);
										if getValue() == sItemName then
											iMinMMPenalty = DB.getValue(vItem, "minimum_mm_penalty", 0);
											iMaxMMPenalty = DB.getValue(vItem, "maximum_mm_penalty", 0);
											iMissilePenalty = DB.getValue(vItem, "missile_penalty", 0);
											iQUPenalty = DB.getValue(vItem, "quickness_penalty", 0);
											iAT = DB.getValue(vItem, "armortype", 1);
											window.equipped_armor_link.setValue("item", DB.getPath(vItem));
										end
									end
								end
							end
							if sOldValue == "" and getValue() == "" then
								
							else
								window.at.setValue(iAT);
								window.mmmin.setValue(iMinMMPenalty);
								window.mmmax.setValue(iMaxMMPenalty);
								window.atmiss.setValue(iMissilePenalty);
								window.qupen.setValue(iQUPenalty);
							end
							window.atname.setValue(getValue());
							window.mmpenalty.setValue(Rules_PC.MMPenalty(window.getDatabaseNode()));
							bIsRefreshing = false;
						end
					end
					
					function handleNameChange()
						if getValue() ~= "" and window.equipped_armor_link then
							local _, sRecordName = window.equipped_armor_link.getValue();
							if sRecordName and sRecordName ~="" then
								local nodeItem = DB.findNode(sRecordName);
								if nodeItem and window.equipped_armor_link.isVisible() then
									setValue(ItemManager2.getDisplayName(nodeItem));
								end
							end
						end
					end

