number_readonly.script:
					function onValueChanged(init)
						refresh();
					end

					function refresh()
						window.mmpenalty.setValue(Rules_PC.MMPenalty(window.getDatabaseNode()));
						if string.lower(OptionsManager.getOption("CCAD")) == string.lower(Interface.getString("option_val_on")) then
							if getValue() == 1 then
								window.dbad.setValue(Rules_PC.AdrenalDefence(window.getDatabaseNode()));
							else
								window.dbad.setValue(0);
							end
							window.dbad.setReadOnly(true);
							window.dbad.setFrame("fieldlight", 4, 4, 4, 4);
						else
							window.dbad.setReadOnly(false);
							window.dbad.setFrame("fielddark", 4, 4, 4, 4);
							window.dbad.setStateFrame("keyedit", "fieldfocus", 4, 4, 4, 4);
						end
					end

					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						
						if getValue()==0 then
							setValue(1);
						end
						OptionsManager.registerCallback("CCAD", refresh);
						refresh();
					end

					function onClose()
						OptionsManager.unregisterCallback("CCAD", refresh);
					end

