number_readonly.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						local nodeChar = window.getDatabaseNode();
						local sPath = DB.getPath(nodeChar, "inventorylist");
						DB.addHandler(sPath, "onChildUpdate", refresh);
						DB.addHandler(sPath .. ".*", "onDelete", refresh);

						local node = window.getDatabaseNode();
						DB.addHandler(DB.getPath(node, "equipped_helmet_link"), "onUpdate", self.refresh);
						DB.addHandler(DB.getPath(node, "equipped_armor_link"), "onUpdate", self.refresh);
						DB.addHandler(DB.getPath(node, "equipped_primary_hand_link"), "onUpdate", self.refresh);
						DB.addHandler(DB.getPath(node, "equipped_secondary_hand_link"), "onUpdate", self.refresh);
						DB.addHandler(DB.getPath(node, "equipped_adder_multiplier_link"), "onUpdate", self.refresh);
						self.refresh();
					end

					function refresh()
						window.db_nonid.setValue(Rules_PC.MagicDBNoID(window.getDatabaseNode()));
						setValue(Rules_PC.MagicDB(window.getDatabaseNode()));
					end

					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						local nodeChar = window.getDatabaseNode();
						local sPath = DB.getPath(nodeChar, "inventorylist");
						DB.addHandler(sPath, "onChildUpdate", refresh);
						DB.addHandler(sPath .. ".*", "onDelete", refresh);

						local node = window.getDatabaseNode();
						DB.addHandler(DB.getPath(node, "equipped_secondary_hand"), "onUpdate", self.refresh);
						self.refresh();
					end

					function refresh()
						setValue(Rules_PC.ShieldDB(window.getDatabaseNode()));
					end

					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						local nodeChar = window.getDatabaseNode();
						DB.addHandler(DB.getPath(Rules_PC.DBStatNode(nodeChar)), "onUpdate", update);
						DB.addHandler(DB.getPath(nodeChar, "dbmagic"), "onUpdate", update);
						DB.addHandler(DB.getPath(nodeChar, "dbad"), "onUpdate", update);
						DB.addHandler(DB.getPath(nodeChar, "dbshield"), "onUpdate", update);
						DB.addHandler(DB.getPath(nodeChar, "dbother"), "onUpdate", update);
						DB.addHandler(DB.getPath(nodeChar, "dbpen"), "onUpdate", update);
						
						update();
					end
					function onClose()
						local nodeChar = window.getDatabaseNode();
						DB.removeHandler(DB.getPath(Rules_PC.DBStatNode(nodeChar)), "onUpdate", update);
						DB.removeHandler(DB.getPath(nodeChar, "dbmagic"), "onUpdate", update);
						DB.removeHandler(DB.getPath(nodeChar, "dbad"), "onUpdate", update);
						DB.removeHandler(DB.getPath(nodeChar, "dbshield"), "onUpdate", update);
						DB.removeHandler(DB.getPath(nodeChar, "dbother"), "onUpdate", update);
						DB.removeHandler(DB.getPath(nodeChar, "dbpen"), "onUpdate", update);
					end

					function update()
						local nStat = Rules_PC.DBStatBonus(window.getDatabaseNode());
						local nMagic = window.dbmagic.getValue();
						local nAD = window.dbad.getValue();
						local nShield = window.dbshield.getValue();
						local nOther = window.dbother.getValue();
						local nPenalty = window.dbpen.getValue();
						if nStat > 0 and nPenalty < 0 then
							nStat = nStat + nPenalty;
							if nStat < 0 then
								nStat = 0;
							end
							window.dbstat_info.setVisible(true);
						else
							window.dbstat_info.setVisible(false);
						end
						window.dbstat.setValue(nStat);
						window.db.setValue(nStat + nMagic + nAD + nOther);
						setValue(nStat + nMagic + nAD + nShield + nOther);
					end

					function action(draginfo)
						local charNode = window.getDatabaseNode();
						local rActor = ActorManager.resolveActor(charNode);
						local sSkillName = ActionSkill.GenericMM;
						local nSkillMod = 0;
						local nSkillType = ActionSkill.MM;
						ActionSkill.performRoll(draginfo, rActor, sSkillName, nSkillMod, nSkillType);
						return true;
					end

					function onDragStart(button, x, y, draginfo)
						return action(draginfo);
					end

					function onDoubleClick(x,y)
						return action();
					end

					function onInit()
						local node = window.getDatabaseNode();
						DB.addHandler(DB.getPath(node, "qupen"), "onUpdate", self.refresh);
						self.refresh();
					end

					function refresh()
						local nPenalty = Rules_PC.ArmorQuicknessPenalty(window.getDatabaseNode());
						setValue(nPenalty);
					end

windowclass.script:
			local sOldRecordName = "";
			
			function onInit()
				if super and super.onInit then
					super.onInit();
				end
				registerMenuItem(Interface.getString("list_menu_deleteitem"), "delete", 6);
				registerMenuItem(Interface.getString("list_menu_deleteconfirm"), "delete", 6, 7);
				
				local nodeItem = DB.getParent(getDatabaseNode());
				local sRecordName = DB.getValue(nodeItem, "recordname", "");

				if sRecordName ~= "" then
					window.open.setValue("item", sRecordName);
					DB.deleteChild(nodeItem, "recordname");
				end
				onLinkChanged();
			end
				
			function onMenuSelection(selection, subselection)
				if selection == 6 and subselection == 7 then
					delete();
				end
			end

			function onLinkChanged()
				local sClass, sRecordName = open.getValue();
				if sOldRecordName ~= "" then
					local nodeOldItem = DB.findNode(sOldRecordName);
					if nodeOldItem then
						DB.removeHandler(DB.getPath(nodeOldItem, "isidentified"), "onUpdate", refreshName);
					end
				end
				sOldRecordName = sRecordName;
				if sRecordName then
					local nodeNewItem = DB.findNode(sRecordName);
					if nodeNewItem then
						DB.addHandler(DB.getPath(nodeNewItem, "isidentified"), "onUpdate", refreshName);
					end
					if string.find(sRecordName, ".inventorylist.") then
						linkFields(sRecordName);
					end
				end
			end
			
			function linkFields(sRecordName)
				local nodeInventoryItem = DB.findNode(sRecordName);
				if nodeInventoryItem then
					name.setLink(DB.createChild(nodeInventoryItem, "name", "string"), true);
					nonid_name.setLink(DB.createChild(nodeInventoryItem, "nonid_name", "string"), true);
					local nodeIsIdentified = DB.findNode(sRecordName .. ".isidentified");
					if nodeIsIdentified then
						isidentified.setLink(nodeIsIdentified, true);
					else
						isidentified.setLink(DB.createChild(nodeInventoryItem, "isidentified", "number"), true);
						DB.setValue(nodeInventoryItem, "isidentified", "number", 1);
					end
					type.setLink(DB.createChild(nodeInventoryItem, "type", "string"), true);
					associatedskill.setLink(DB.createChild(nodeInventoryItem, "associatedskill", "string"), true);
					rng1.setLink(DB.createChild(nodeInventoryItem, "rng1", "number"), true);
					mod1.setLink(DB.createChild(nodeInventoryItem, "mod1", "number"), true);
					rng2.setLink(DB.createChild(nodeInventoryItem, "rng2", "number"), true);
					mod2.setLink(DB.createChild(nodeInventoryItem, "mod2", "number"), true);
					rng3.setLink(DB.createChild(nodeInventoryItem, "rng3", "number"), true);
					mod3.setLink(DB.createChild(nodeInventoryItem, "mod3", "number"), true);
					rng4.setLink(DB.createChild(nodeInventoryItem, "rng4", "number"), true);
					mod4.setLink(DB.createChild(nodeInventoryItem, "mod4", "number"), true);
					rng5.setLink(DB.createChild(nodeInventoryItem, "rng5", "number"), true);
					mod5.setLink(DB.createChild(nodeInventoryItem, "mod5", "number"), true);
					rng6.setLink(DB.createChild(nodeInventoryItem, "rng6", "number"), true);
					mod6.setLink(DB.createChild(nodeInventoryItem, "mod6", "number"), true);
					
					ob_nonid.setLink(DB.createChild(nodeInventoryItem, "ob_nonid", "number"), true);
					ob.setLink(DB.createChild(nodeInventoryItem, "ob", "number"), true);
					fumble.setLink(DB.createChild(nodeInventoryItem, "fumble", "number"), true);
					meleebonus.setLink(DB.createChild(nodeInventoryItem, "meleebonus", "number"), true);
					missilebonus.setLink(DB.createChild(nodeInventoryItem, "missilebonus", "number"), true);
				end
			end

			function delete()
				local node = getDatabaseNode();
				local nodeChar = DB.getChild(node, "...");
				if not node then
					close();
					return;
				end
				local sClass, sRecordName = DB.getValue(node, "open", nil);
				if not sRecordName or sRecordName == "" then
					DB.deleteNode(node);
				elseif sRecordName and string.find(sRecordName, ".inventorylist.") then
					nodeItem = DB.findNode(sRecordName);
					if nodeItem then
						ItemManager2.charRemoveItem(nodeItem);
						DB.deleteNode(nodeItem);
					else
						DB.deleteNode(node);
					end
				else
					DB.deleteNode(node);
				end
			end

			function isWeapon()
				local node = getDatabaseNode();
				local vType = DB.getValue(node, "type", 0);
				if vType == "Shield" or vType == 7 then
					return false; 
				else
					return true;
				end
			end
			
			function refreshName()
				local bID = true;
				local sClass, sRecordName = DB.getValue(getDatabaseNode(), "open", nil);
				if sRecordName ~= "" then
					local nodeLink = DB.findNode(sRecordName);
					if nodeLink then
						bID = (DB.getValue(nodeLink, "isidentified", 1) == 1);
					end
				end

				if bID then
					displayname.setValue(name.getValue());
				else
					displayname.setValue(nonid_name.getValue());
				end
			end

