function onInit()
	if super and super.onInit then
		super.onInit();
	end
	refresh();
end

function onValueChanged()
	if super and super.onValueChanged then
		super.onValueChanged();
	end
	refresh();
end

function refresh()
	local iswpn = window.isWeapon();
	window.table.setVisible(iswpn);
	window.dblabel1.setVisible(not iswpn);
	window.dblabel2.setVisible(not iswpn);
	window.ob.setVisible(iswpn);
	window.meleebonus.setVisible(not iswpn);
	window.missilebonus.setVisible(not iswpn);
	window.fumble.setVisible(iswpn);
	window.ranges.setVisible(iswpn);
	if Session.IsHost then
		window.ob_nonid.setVisible(iswpn);
	else
		window.ob_nonid.setVisible(false);
	end
end

string_listitem_right_noframe_static.script:
					local suspend = false;

					function onInit()
						if super and super.onInit then
							super.onInit();
						end

						local node = window.getDatabaseNode();
						local sClass, sRecordName = DB.getValue(node, "open", nil);
						if sRecordName and string.find(sRecordName, ".inventorylist.") then
							node = DB.findNode(sRecordName);
						end

						if node then
							for r=1,6 do
								local nodeMod = DB.createChild(node, "mod"..r,"number");
								DB.addHandler(DB.getPath(nodeMod), "onUpdate", self.recalc);
								local nodeRng = DB.createChild(node, "rng"..r,"number");
								DB.addHandler(DB.getPath(nodeRng), "onUpdate", self.recalc);
							end
							local nodeRngSlots = DB.createChild(node, "rngslots","number");
							DB.addHandler(DB.getPath(nodeRngSlots), "onUpdate", self.recalc);
						end
						recalc();
					end

					function recalc()
						local node = window.getDatabaseNode();
						local sClass, sRecordName = DB.getValue(node, "open", nil);
						if sRecordName and string.find(sRecordName, ".inventorylist.") then
							node = DB.findNode(sRecordName);
						end

						if node then
							local rng = window.rngslots.getValue();
							local rangetext = "";
							if suspend then
								return;
							else
								suspend = true;
							end
							local nRanges = 0;
							for r=1,6 do
								local nRange = DB.getValue(node, "rng" .. r, -1);
								local nMod = DB.getValue(node, "mod" .. r, 0);
								if nMod ~= 0 then
									nRanges = nRanges + 1;
								end
								if nRange > -1 and nRanges > 0 then
									local modtxt = nMod;
									if modtxt >= 0 then
										modtxt = "+" .. modtxt;
									end
									if r==1 then
										rangetext = nRange .. ": " .. modtxt;
									else
										rangetext = rangetext .. ", " .. nRange .. ": " .. modtxt;
									end
								end
							end

							setValue(rangetext);
							suspend = false;
						end
					end

string_listitem_center_noframe_static.script:
function onValueChanged()
	if getValue() == "item" and getValue() == window.name.getValue() then
		setValue(window.name.getValue());
	end
end
